record.field:
contacts = model.search([('x_subscribe', '=', True)])
mail_template = env['mail.template'].search([('id','=',env.ref('real_estate.mail_template_42'))])
for contact in contacts:
    if contact.x_to_notify_properties:
        res = mail_template.send_mail(res_id=contact.id)
        if res:
            contact.write({'x_last_notification': datetime.datetime.now()})

if not record.website_ribbon_id.x_is_draft_ribbon and not record.website_ribbon_id.x_is_closed_ribbon:
    if not record.x_ribbon_stage_is_accounted:
        record['x_ribbon_stage_is_accounted'] = True
        record['x_last_notification_update'] = datetime.datetime.now()#.strftime('%Y-%m-%d %H:%M:%S')

if len(record.message_ids) == 1 and not record.x_interested_in :
    properties = env["product.template"].search([])
    for property in properties:
        for reference in property.x_other_ads:
            if reference.x_name in record.message_ids[0].body or reference.x_name in record.message_ids[0].subject or reference.x_name in record.message_ids[0].email_from:
                record["x_interested_in"] = property.id

for record in records:
    commission_plan = env['sale.commission.plan'].search([('name', '=', 'Commission Plan 2025')], limit=1)
    if record.move_type == 'out_invoice' or record.state != 'posted' and commission_plan:
        if record.x_seller and record.x_seller.id != record.invoice_user_id.id:
            plan_user_id_finder = env['sale.commission.plan.user'].search([
                ('plan_id', '=', commission_plan.id),
                ('user_id', '=', record.invoice_user_id.id),
            ])
            plan_user_id_seller = env['sale.commission.plan.user'].search([
                ('plan_id', '=', commission_plan.id),
                ('user_id', '=', record.x_seller.id),
            ])
            if plan_user_id_finder and plan_user_id_seller:
                adjustment = env['sale.commission.achievement'].create({
                    'achieved': record.amount_untaxed * 0.10,
                    'currency_id': record.currency_id.id,
                    'display_name': record.name,
                    'add_user_id': plan_user_id_seller.id,
                    'reduce_user_id': plan_user_id_finder.id,
                    'company_id': record.company_id.id,
      })

for rec in records:
    if not rec.partner_id or not rec.x_interested_in.x_owner:
        raise UserError("Missing signer: Customer or Owner is not set.")
    act = rec.env['ir.actions.act_window']._for_xml_id('sign.action_sign_send_request')
    act['context'] = {
        'default_template_id': env.ref('real_estate.sign_template_3').id,
        "active_id": rec.id,
        "default_res_model": "crm.lead",
        "default_res_id": rec.id,
        'default_set_sign_order': True,
        'default_property': rec.x_interested_in,
        'default_signer_ids': [
            (0, 0, {
                'partner_id': rec.partner_id.id,
                'role_id': env.ref('real_estate.sign_item_role_9').id,
            }),
            (0, 0, {
                'partner_id': rec.x_interested_in.x_owner.id,
                'role_id': env.ref('real_estate.sign_item_role_10').id,
            }),
        ],
        "default_reference_doc": f"crm.lead,{rec.id}"
    }
    action = act
